    Album(id: 3, title: "Purple Rain", artist: "Prince", year: 1984, genre: "Pop", tracks: 9, rating: 4.7),
    Album(id: 4, title: "Thriller", artist: "Michael Jackson", year: 1982, genre: "Pop", tracks: 9, rating: 4.8),
